class Solution:
    def longestIncrSubSeqSum(self, nums: list[int]) -> int:
        dp = [[0]*n for _ in range(n)]
        for i in range(n):
            dp[i][i] = nums[i]
        for len in range(2, n + 1):
            for i in range(n - len + 1):
                j = i + len - 1
                dp[i][j] = max(nums[j], dp[i][j - 1] + nums[j])
        max_sum = 0
        for i in range(n):
            for j in range(i, n):
                max_sum = max(max_sum, dp[i][j])
        return max_sum

